import{_ as i,o as a,c as e,ai as o}from"./chunks/framework.DwK_gMmt.js";const p=JSON.parse('{"title":"NC 500 (North Coast 500)","description":"","frontmatter":{"date":"2025-07-14 12:50:35 +0100","categories":"uk scotland"},"headers":[],"relativePath":"trips/nc-500.md","filePath":"trips/nc-500.md"}'),r={name:"trips/nc-500.md"};function t(n,l,s,h,c,u){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="nc-500-north-coast-500" tabindex="-1">NC 500 (North Coast 500) <a class="header-anchor" href="#nc-500-north-coast-500" aria-label="Permalink to “NC 500 (North Coast 500)”">​</a></h1><p><img src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT5qB2C6a6gwOTtczGEhw2mtPOQqDki1hz71YK4lQMgtA&amp;s=10" alt=""></p><p>Fuel/petrol: Handy to fill up in Thurso, Ullapool, Inverness—prices vary</p><h2 id="day-1-sat-jul-5" tabindex="-1">Day 1 - SAT - JUL 5 <a class="header-anchor" href="#day-1-sat-jul-5" aria-label="Permalink to “Day 1 - SAT - JUL 5”">​</a></h2><ul><li>Glasgow</li><li>Fort Augustus</li><li>Loch Ness - Ness shores <ul><li>LUNCH</li></ul></li><li>Urquhart Castle</li><li>Culloden - famous battlefield of Culloden, where the historic final confrontation of the 1745 Jacobite Uprising took place</li><li>Clava Cairns - 4k year old stone circles, an important place for ritual and burial activities in the Bronze Age</li><li>Inverness - Fort George view or chill in Inverness <ul><li>River House Café</li><li>take a sunset walk along the River Ness.</li><li>Perk in Inverness: top‑notch coffee + doughnuts + vegan options</li><li><strong>Stay</strong>: Inverness hotel—consider centrally located to explore or</li></ul></li></ul><h2 id="day-2-sun-jul-6" tabindex="-1">Day 2 - SUN - JUL 6 <a class="header-anchor" href="#day-2-sun-jul-6" aria-label="Permalink to “Day 2 - SUN - JUL 6”">​</a></h2><ul><li>Inverness</li><li>Culloden Battlefield near inverness</li><li>Black Isle - Grab craft beers at Black Isle Brewery</li><li>Chanonry Point - dolphin spotting</li><li>Cromarty - dolphin spotting, explore and coffee</li><li>Light distillery tour at Glenmorangie.</li><li>Dingwall</li><li>Tain <ul><li>Pipers Coffee House—great toasties and cakes</li><li>LUNCH</li></ul></li><li>Glenmorangie Distillery</li><li>Dornoch <ul><li>explore cathedral &amp; beach</li><li>sunset on the estuary</li><li>Dinner at Dornoch Castle Hotel</li><li>Stay: Dornoch Castle hotel or boutique stay in the town centre.</li></ul></li></ul><h2 id="day-3-mon-jul-7" tabindex="-1">Day 3 - MON - JUL 7 <a class="header-anchor" href="#day-3-mon-jul-7" aria-label="Permalink to “Day 3 - MON - JUL 7”">​</a></h2><ul><li>Dornoch</li><li>Dunrobin Castle</li><li>Helmsdale (east coast)</li><li>Whaligoe Steps</li><li>Wick <ul><li>Food - Puldagon Farm Shop for rustic farm‑to‑plate meals</li></ul></li><li>John O’Groats - signpost photos, explore</li><li>Dunnet Head - getting up top at Dunnet Head for sunset <ul><li>for puffins, WWII bunkers &amp; sunset</li></ul></li><li>Thurso <ul><li>Cafe Tempest—surf‑vibe café good for lunch</li><li>fish &amp; chips at Halladale Inn</li><li>Stay: Charming B&amp;B or small hotel in Thurso</li></ul></li></ul><h2 id="day-4-tue-jul-8" tabindex="-1">Day 4 - TUE - JUL 8 <a class="header-anchor" href="#day-4-tue-jul-8" aria-label="Permalink to “Day 4 - TUE - JUL 8”">​</a></h2><ul><li>Thurso - Thurso/Bettyhill area for early wildlife start next day</li><li>Tongue - Tongue photo stop (Kyle of Tongue bridge area) <ul><li>Tongue viewpoint (great loch shot)</li></ul></li><li>Smoo Cave walk &amp; optional boat trip</li><li>Cocoa Mountain in Balnakeil - Cocoa Mountain Cafe for legendary hot chocolate &amp; brownies</li><li>Durness (via Cape Wrath detour) <ul><li>Durness Beach (superb white sands)</li></ul></li><li>Scenic drive through Kylesku Bridge</li><li>Lochinver <ul><li>Dinner in Lochinver: Lochinver Larder pies or Driftwood Café for light fare</li><li>Stay: coastal Cabin or B&amp;B in Lochinver or a beachside cottage</li></ul></li></ul><h2 id="day-5-wed-jul-9" tabindex="-1">Day 5 - WED - JUL 9 <a class="header-anchor" href="#day-5-wed-jul-9" aria-label="Permalink to “Day 5 - WED - JUL 9”">​</a></h2><ul><li>Lochinver <ul><li>Quick sunrise stroll at Clachtoll Broch or Achmelvich Beach</li><li>Ardvreck Castle/Calda House photography stop</li></ul></li><li>Ullapool <ul><li>Whale watching near Ullapool or visit Knockan Crag</li><li>Corrieshalloch Gorge (short walk, 30–45 min)</li><li>Food : Ullapool: freshest langoustines &amp; mussels</li></ul></li><li>Quick stop at Kylesku Bridge (photo)</li><li>Gairloch <ul><li>Black Pearl Creole Kitchen, Gairloch—unexpected Caribbean twist</li><li>stop at beach or café</li></ul></li><li>Torridon <ul><li>drive stunning coast</li><li>Stay: Torridon Hotel (5★), or cozy B&amp;B nearby.</li><li>In Torridon, enjoy a dram and live music at the Torridon bar</li></ul></li></ul><h1 id="day-6-thu-jul-10" tabindex="-1">Day 6 - THU - JUL 10 <a class="header-anchor" href="#day-6-thu-jul-10" aria-label="Permalink to “Day 6 - THU - JUL 10”">​</a></h1><ul><li>Torridon <ul><li>Sunrise via Pulpit Rock viewpoint (Glen Torridon)</li><li>Light bites at Torridon</li></ul></li><li>Bealach na Bà pass north Applecross (one of UK’s most dramatic roads) <ul><li>Bealach na Bà pass drive</li><li>photo pass</li><li>a cosy stop in Applecross pub (if open) - fish chips</li></ul></li><li>Lunch in Lochcarron or scenic picnic</li><li>Achnasheen</li><li>Eilean Donan Castle &amp; iconic views.</li><li>Kyle of Lochalsh <ul><li>Stay: Hotel or B&amp;B in Kyle of Lochalsh with views over the castle.</li><li>Stay: Kyle of Lochalsh hotel with castle views.</li></ul></li><li>Lochalsh <ul><li>Dinner in Kyle of Lochalsh – numerous local eateries; check local catch options</li></ul></li></ul><h1 id="day-7-fri-jul-11" tabindex="-1">Day 7 - FRI - JUL 11 <a class="header-anchor" href="#day-7-fri-jul-11" aria-label="Permalink to “Day 7 - FRI - JUL 11”">​</a></h1><ul><li>Kyle <ul><li>Quick stop at Glen Ord or Glenmorangie Distillery en route</li><li>Loch Garry / Glenshiel photo stop</li></ul></li><li>Invermoriston Falls</li><li>Loch Ness photo stop</li><li>Inverness <ul><li>Quick walk/coffee in Inverness</li><li>Revisit Loch Ness, maybe take a boat trip.</li><li>Lunch in Inverness.</li></ul></li><li>Drive via Rannoch Moor &amp; Glencoe (James Bond/Skyfall locations)</li><li>Glasgow (via A9) <ul><li>Arrive Glasgow by evening.</li></ul></li></ul>',17)])])}const y=i(r,[["render",t]]);export{p as __pageData,y as default};
